import numpy as np
from scipy.stats import beta as beta_dist

# === Epsilon-Greedy ===
class EpsilonGreedy:
    def __init__(self, n_arms, epsilon=0.1):
        self.n_arms = n_arms
        self.epsilon = epsilon
        self.counts = np.zeros(n_arms)  # times arm pulled
        self.values = np.zeros(n_arms)  # average reward per arm

    def select_arm(self):
        if np.random.random() < self.epsilon:
            return np.random.randint(self.n_arms)
        return np.argmax(self.values)

    def update(self, arm, reward):
        self.counts[arm] += 1
        # Incremental update of mean
        n = self.counts[arm]
        self.values[arm] += (reward - self.values[arm]) / n

# === Upper Confidence Bound (UCB1) ===
class UCB1:
    def __init__(self, n_arms):
        self.n_arms = n_arms
        self.counts = np.zeros(n_arms)
        self.values = np.zeros(n_arms)
        self.t = 0

    def select_arm(self):
        self.t += 1
        # Pull each arm once first
        for arm in range(self.n_arms):
            if self.counts[arm] == 0:
                return arm

        # UCB: upper confidence bound
        bonus = np.sqrt(2 * np.log(self.t) / self.counts)
        ucb = self.values + bonus
        return np.argmax(ucb)

    def update(self, arm, reward):
        self.counts[arm] += 1
        n = self.counts[arm]
        self.values[arm] += (reward - self.values[arm]) / n

# === Thompson Sampling (Bayesian) ===
class ThompsonSampling:
    def __init__(self, n_arms):
        self.n_arms = n_arms
        # Beta prior: Beta(1, 1) = Uniform
        self.alpha = np.ones(n_arms)
        self.beta = np.ones(n_arms)

    def select_arm(self):
        # Sample from posterior
        samples = beta_dist.rvs(self.alpha, self.beta)
        return np.argmax(samples)

    def update(self, arm, reward):
        # reward in {0, 1} for Bernoulli bandit
        if reward == 1:
            self.alpha[arm] += 1
        else:
            self.beta[arm] += 1

# === EXP3 (Adversarial bandits) ===
class EXP3:
    def __init__(self, n_arms, gamma=0.1):
        self.n_arms = n_arms
        self.gamma = gamma  # exploration probability
        self.weights = np.ones(n_arms)

    def select_arm(self):
        # Probability distribution over arms
        probs = (1 - self.gamma) * self.weights / self.weights.sum() \
                + self.gamma / self.n_arms
        return np.random.choice(self.n_arms, p=probs), probs

    def update(self, arm, reward, probs):
        # Importance-weighted reward estimate (unbiased)
        estimated_reward = reward / probs[arm]
        self.weights[arm] *= np.exp(self.gamma * estimated_reward / self.n_arms)

# === Regret simulation ===
def simulate_bandit(bandit_algo, n_rounds=1000):
    """Simulate a Bernoulli bandit with unknown means."""
    true_means = [0.1, 0.3, 0.5, 0.7, 0.9]
    optimal = max(true_means)

    regrets = []
    for t in range(n_rounds):
        arm = bandit_algo.select_arm()
        reward = np.random.binomial(1, true_means[arm])
        bandit_algo.update(arm, reward)
        regret = optimal - true_means[arm]
        regrets.append(regret)

    return np.cumsum(regrets)
